from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from jwt import encode, decode
import datetime
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)

db.create_all()

SECRET_KEY = os.environ.get('SECRET_KEY') or 'your-secret-key'
ALGORITHM = 'HS256'
ACCESS_TOKEN_EXPIRE_MINUTES = 300

def authenticate(username, password):
    user = User.query.filter_by(username=username).first()
    if user and user.password == password:
        return user

def encode_auth_token(user_id):
    try:
        payload = {
            'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES),
            'iat': datetime.datetime.utcnow(),
            'jti': user_id,
            'sub': user_id
        }
        token = jwt.encode(
            payload, SECRET_KEY, algorithm=ALGORITHM)
        return token.decode('utf-8')
    except Exception as e:
        return None

def decode_auth_token(token):
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return User.query.get(payload['sub'])
    except:
        return None

@app.route('/register', methods=['POST'])
def register():
    if not request.is_json:
        return jsonify({'error': 'Expecting JSON'}), 400

    data = request.get_json()

    new_user = User(username=data['username'], password=data['password'])
    db.session.add(new_user)
    db.session.commit()

    return jsonify({'message': 'User created successfully'}), 201

@app.route('/login', methods=['POST'])
def login():
    if not request.is_json:
        return jsonify({'error': 'Expecting JSON'}), 400

    data = request.get_json()

    user = authenticate(data['username'], data['password'])
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401

    token = encode_auth_token(user.id)
    return jsonify({'token': token}), 200

@app.route('/protected', methods=['GET'])
@jwt_required()
def protected():
    return jsonify({'message': 'This resource is protected. You need to be authenticated to access it.'})

@app.route('/refresh')
@jwt_required()
def refresh():
    current_user = decode_auth_token(jwt_token)
    new_token = encode_auth_token(current_user.id)
    return jsonify({'token': new_token}), 200

def jwt_required():
    def wrap(*args, **kwargs):
        def wrapper(*arg, **kwarg):
            jwt_header = request.headers.get('Authorization')
            if not jwt_header:
                return jsonify({'error': 'Authorization token is missing'}), 401

            try:
                user_id = decode_auth_token(jwt_header.split(" ")[1])
            except:
                return jsonify({'error': 'Invalid token'}), 401

            kwarg['current_user'] = user_id
            return wrapper(*args, **kwargs)
        return wrapper
    return wrap

if __name__ == '__main__':
    app.run(debug=True)